import torch
import torch.nn as nn
from torch.utils.cpp_extension import load_inline

cuda_src = """
#include <torch/extension.h>
#include <cublas_v2.h>

static cublasHandle_t handle = nullptr;

__global__ void bias_relu_kernel(float* C, const float* bias, int M, int N) {
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (idx >= M * N) return;
    int col = idx % N;
    float val = C[idx] + bias[col];
    C[idx] = val > 0.0f ? val : 0.0f;  // fused ReLU
}

torch::Tensor gemm_bias_relu(torch::Tensor A, torch::Tensor B, torch::Tensor bias) {
    if (!handle) cublasCreate(&handle);
    int M = A.size(0), K = A.size(1), N = B.size(1);
    auto C = torch::empty({M, N}, A.options());
    float alpha = 1.0f, beta = 0.0f;
    cublasSgemm(handle, CUBLAS_OP_N, CUBLAS_OP_N,
                N, M, K, &alpha,
                B.data_ptr<float>(), N,
                A.data_ptr<float>(), K,
                &beta, C.data_ptr<float>(), N);
    // Fused epilogue: bias + ReLU in one pass
    int total = M * N;
    bias_relu_kernel<<<(total+255)/256, 256>>>(C.data_ptr<float>(), bias.data_ptr<float>(), M, N);
    return C;
}
"""

cpp_src = "torch::Tensor gemm_bias_relu(torch::Tensor, torch::Tensor, torch::Tensor);"
epilogue_mod = load_inline(name='epilogue_fusion', cpp_sources=cpp_src,
                           cuda_sources=cuda_src, extra_ldflags=['-lcublas'],
                           functions=['gemm_bias_relu'])

class ModelNew(nn.Module):
    def __init__(self, in_features, out_features):
        super().__init__()
        self.weight = nn.Parameter(torch.randn(in_features, out_features))
        self.bias = nn.Parameter(torch.zeros(out_features))

    def forward(self, x):
        return epilogue_mod.gemm_bias_relu(x.contiguous(), self.weight.contiguous(), self.bias)
